import React from "react";

function Home() {
  return (
    <div
      style={{
        textAlign: "center",
        marginTop: "80px",
        fontFamily: "Arial, sans-serif",
        padding: "20px",
      }}
    >
      <img
        src="/profile.jpg"
        alt="Shubham Ugale"
        style={{
          width: "170px",
          borderRadius: "50%",
          boxShadow: "0 5px 20px rgba(0,0,0,0.3)",
        }}
      />

      <h1 style={{ marginTop: "20px", fontSize: "32px" }}>
        Shubham Ugale
      </h1>

      <h3 style={{ color: "gray", marginTop: "10px" }}>
        Game Developer
      </h3>

      <p
        style={{
          maxWidth: "500px",
          margin: "20px auto",
          lineHeight: "1.6",
          color: "#555",
        }}
      >
        Passionate Game Developer focused on building immersive and interactive
        gaming experiences using modern technologies.
      </p>
    </div>
  );
}

export default Home;
